local _subNameToChannel = {
    ["qianxi2"] = "seachannel1",
    ["qianxidev"] = "seachannel1",
    ["qianxi3"] = "seachannel2",
    ["qianxi3dev"] = "seachannel2",

    ["qianxi4"] = "seachannel3",
    ["qianxi4dev"] = "seachannel3",
