---@param payPointRef V_WelfareProductPayPointRef
function LSdkCpQianxi:GetProductParam(payPointRef)
    local produceCp = payPointRef.seachannel

    local pfTitle = LGameSettings.platformTitle
    local channelName = _subNameToChannel[pfTitle]
    if string.isempty(channelName) then
        if LGameSettings.platformRegion == LRegionConst.VIETNAM then
            channelName = "vndchannel"
        elseif LGameSettings.platformRegion == LRegionConst.RUS then
            channelName = "rubchannel"
        end
    end
    if not string.isempty(channelName) then
        produceCp = payPointRef[channelName]
    end
    local money = payPointRef.usdPayPoint
    return produceCp, money, "USD"
end

local _emptyProductName = {
    --["qianxileidian"] = true,
}
function LSdkCpQianxi:OnInternalCreateOrderOk(orderData)
    local payData = orderData.payData
    local tgaData = orderData.tgaData
    local extraData = orderData.extraData
    local objJson = LxHttpHelper.CheckWebJson(CS.YXWebRet.ok,orderData.orderId)
    if (not objJson) then
        return
    end
    local sOutOrderNo = tostring(objJson.msg)
    local sSign = objJson.cp_sign

    local callBackUrl = gLGameLogin:GetCallBackUrl()

    local sMoney = tostring(payData.money)
    local coinsAmount = payData.diamonds or 0
    local productName = payData.productName or ""
    local sProductDesc = productName
    if _emptyProductName[LGameSettings.platformTitle] then
        sProductDesc = ""
    end
    local sProductId = extraData.produceCp or ""

    if gLxTKData then
        tgaData.orderId = sOutOrderNo
        gLxTKData:OnPayTAReq(tgaData)
    end

    local sRoleId = gModelPlayer:GetPlayerId() or 0
    local sRoleName = gModelPlayer:GetPlayerName() or ""
    local sRoleLevel = gModelPlayer:GetPlayerLv() or 0

    local sServerId = gLGameLogin:GetServerId() or 0
    local sServerName = gLGameLogin:GetServerName() or ""

    local callBackStr = extraData.callBackInfo

    self._impl:SendCpNativeMessage("Pay", sOutOrderNo, callBackUrl, callBackStr, sMoney,
            sProductId, sProductDesc, sServerId, sServerName, sRoleId, sRoleName, sRoleLevel)
end

