    end
    return false
end
function LSdkCpQianxi:ReqNotificationPermission(isShowSetting)
    if CS.IsOSIos() then
        local permission = "Notification"
        self._impl:SendCpNativeMessage("RequestPermissionByX", permission)
    elseif CS.IsOSAndroid() then
        local apiLv = LNativeHelper.GetCurrentApiVersion()
        if apiLv < 33 then return end
        local permission = "android.permission.POST_NOTIFICATIONS"
        if LNativeHelper.CheckPermission(permission) then
            return
        end
        local tips = ""
        local okStr = ccClientText(19788)
        local cancelStr = ccClientText(19789)
        local settingStr = ""
        if isShowSetting then
            settingStr = ccClientText(19791)
        end
        self._impl:SendCpNativeMessage("RequestPermissionByX", tips, okStr, cancelStr, settingStr, permission)
    end

end

