function LSdkCpQianxi:UploadRole(roleType)
    local roleId = gLGameLogin:GetPlayerId() or 0
    local roleName = ""
    local roleLevel = 0
    local sServerId = gLGameLogin:GetServerId() or "0"
    local sServerName = gLGameLogin:GetServerName() or ""
    local roleVip =0
    local money = 0
    if roleType == 1 then
        local playerData = gLGameLogin:GetPlayerData()
        if not playerData then return end
        roleName = playerData.name
        roleLevel = tonumber(playerData.level) or 0
        roleVip = tonumber(playerData.vipLevel) or 0
    else
        roleName = gModelPlayer:GetPlayerName() or ""
        roleLevel = gModelPlayer:GetPlayerLv() or 0
        roleVip = gModelPlayer:GetVipLevel() or 0
        money = gModelItem:GetNumByRefId(ModelItem.ITEM_DIAMOND)
    end

    self._impl:SendCpNativeMessage("UploadRole", roleType,  roleId, roleName, roleLevel, roleVip , sServerId , sServerName, money)
end

function LSdkCpQianxi:IsSupportShareChannel(channel)
    if channel ~= LShareConst.SCENE_FACE_BOOK then
        return false
    end
    local funcTypeShare = _ExtendFuncType.SHARE_IMG -- //"SHARE_URL"
    if self:IsFunctionSupported(funcTypeShare) then
