function LSdkCpQianxi:Share(shareData)
    local shareType = tonumber(shareData.forType)
    if not shareType then return end
    if CS.IsOSAndroid() then
        local extendFuncType = nil
        if shareType == LShareConst.SHARE_TY_IMAGE then
            extendFuncType = _ExtendFuncType.SHARE_IMG
        elseif shareType == LShareConst.SHARE_TY_TEXT then
            extendFuncType = _ExtendFuncType.SHARE_URL
        else
            return
        end
        if not self:IsFunctionSupported(extendFuncType) then
            return
        end
        self._impl:SendCpNativeMessage("Share", extendFuncType)
    else if CS.IsOSIos() then
        local extendFuncType = nil
        if shareType == LShareConst.SHARE_TY_IMAGE then
            extendFuncType = 2
        elseif shareType == LShareConst.SHARE_TY_TEXT then
            extendFuncType = 1
        else
            return
        end
        self._impl:SendCpNativeMessage("Share", extendFuncType)
    end
    end
end

