--on cp message
function LSdkCpQianxi:OnLoginResult(args)
    local isOk = toboolean(args[1])
    if isOk then
        self._sUserId = args[2]
        self._sUserName = args[3]
        self._sSign = args[4]
        self._sTimestamp = args[5]
        LNativeHelper.SetReportUserId(self._sUserId)
        self:_InternalStartWebValidUser()
        --self:ProductDetails()
    else
        self._sUserId = ""
        self._sUserName = ""
        self._sSign = ""
        self._sTimestamp = ""

        self:LoginFailure()
    end
end

function LSdkCpQianxi:_InternalStopWebValidUser()
    if self._webReq then
        self._webReq:Destroy()
        self._webReq = nil
    end
end

function LSdkCpQianxi:_InternalStartWebValidUser()
    if string.isempty(self._sUserId) then return end
    self._isValidUser = false
    local webReq = self._webReq
    if webReq and not webReq:IsDestroy() then
        if webReq:IsSameValidReqParam(self._sUserId .. self._sSign) then -- 同样的验证码
            if not webReq:IsFinished() or webReq:IsOK() then
                --正在请求或者，已经请求成功了获得了结果，不再请求
                return
            end
        end
    end

    self:_InternalStopWebValidUser()

    webReq = LCpWebReq:New()
    self._webReq = webReq

    webReq:SetValidReqParam(self._sUserId .. self._sSign)

    local sUserId = self._sUserId
    local sSign = self._sSign
    local sTimestamp = self._sTimestamp

    local sign = string.upper(CS.md5FromString(sUserId..sSign..sTimestamp..LGameLogin.AuthKey))

    local tokenTbl = {
        "userId="..sUserId,
        "userSign="..sSign,
        "userTimestamp="..sTimestamp,
        "sign="..sign
    }
    local paramPart = table.concat(tokenTbl, "&")
    local params = "qx/loginVerify.do?"..paramPart

    local urlList = gLGameLogin:GetServicesUrlList()

    webReq:StartReq(urlList, params, function (ret, result)
        if ret ~= CS.YXWebRet.ok then
            GF.ShowMessage(ccClientText(140))
            LogError("AuthCodeError ...")
            self:_InternalStopWebValidUser() --销毁可以进行下次验证
            self:LoginFailure()
        else
            local code = tostring(result.code)
            if(code == "0") then
                self._isValidUser = true
                self:LoginOk()
            else
                GF.ShowMessage(ccClientText(140))
                LogError("error AuthCode response code = "..tostring(code))
                self:_InternalStopWebValidUser() --销毁可以进行下次验证
                self:LoginFailure()
            end
        end
    end,true)
end

function LSdkCpQianxi:OnLogoutResult(args)
    local isOk = toboolean(args[1])
    if isOk then
        local sUserId = args[2]
        if sUserId == self._sUserId then
            self._isValidUser = false
            self._sUserId = ""
            self:LogoutOk()
        end
    end
end

