function LSdkCpQianxi:OnProductDetailsResult(args)
    local isOk = toboolean(args[1])
    if isOk then
        local data = args[2]
        local jsonData = JSON.decode(data)
        self._listProductDetail = {}
        self._mapProductDetail = {}
        if not jsonData then return end
        self._productDetailCode = jsonData.code
        local products = jsonData.products
        self._listProductDetail = products
        for k, v in ipairs(products) do
            self._mapProductDetail[v.id] = v
        end
    end
end

function LSdkCpQianxi:OnAdviewResult(args)
    local isOk = toboolean(args[1])
    if isOk then
        --- 发送协议
        FireEvent(EventNames.ADSSHOP_OPEN_FINISH)
    else
        FireEvent(EventNames.ADSSHOP_OPEN_ERROR)
    end
end

